+        AllocationDomain::IrArena,
+        AllocationDomain::EvidenceArena,
+        AllocationDomain::ScratchBuffer,
+    ];
+    for d in &all {
+        let s = d.to_string();
+        assert_eq!(s, s.to_lowercase(), "Display must be lowercase kebab-case");
+    }
+}
