+#[test]
+fn enrichment_budget_serde_json_field_names() {
+    let budget = DomainBudget::new(512);
+    let json = serde_json::to_string(&budget).unwrap();
+    let v: serde_json::Value = serde_json::from_str(&json).unwrap();
+    let obj = v.as_object().unwrap();
