+#[test]
+fn enrichment_domain_config_serde_roundtrip_all_variants() {
+    let all_domains = [
+        AllocationDomain::ExtensionHeap,
+        AllocationDomain::RuntimeHeap,
+        AllocationDomain::IrArena,
+        AllocationDomain::EvidenceArena,
+        AllocationDomain::ScratchBuffer,
