+fn epoch(n: u64) -> SecurityEpoch {
+    SecurityEpoch::from_raw(n)
+}
+
+fn make_alarm(id: &str, domain: ShiftDomain, severity: ShiftSeverity, raised: u64) -> ShiftAlarm {
+    ShiftAlarm::new(
+        id.to_string(),
+        domain,
+        severity,
+        epoch(raised),
+        100_000, // drift_magnitude
+        format!("alarm {id}"),
+    )
+}
+
+fn make_acquisition(
+    domain: ShiftDomain,
+    acquired: u64,
+    needed: u64,
+    status: AcquisitionStatus,
+    last_epoch: u64,
+) -> AcquisitionEvidence {
+    let velocity = if acquired > 0 { 10_000 } else { 0 };
+    AcquisitionEvidence::new(
+        domain,
+        acquired,
+        needed,
+        status,
+        epoch(last_epoch),
+        velocity,
+    )
+}
+
+fn make_claim(id: &str, surface: ClaimSurface, confidence: u64) -> BenchmarkClaim {
+    BenchmarkClaim::new(
+        id.to_string(),
+        surface,
+        confidence,
+        epoch(1),
+        format!("claim {id}"),
+    )
+}
